use crate::types::{DecideInput, DecideOutput, Parameters};

pub fn decide(input: &DecideInput) -> DecideOutput {
    let numpoints = input.numpoints;
    let x = &input.x;
    let y = &input.y;
    let params = &input.parameters;
    let lcm = &input.lcm;
    let pum_diag = &input.pum_diag;

    let mut cmv = vec![false; 15];

    cmv[0] = lic1(x, y, numpoints, params.length1);
    cmv[1] = lic2(x, y, numpoints, params.radius1);
    cmv[2] = lic3(x, y, numpoints, params.epsilon);
    cmv[3] = lic4(x, y, numpoints, params.area1);
    cmv[4] = lic5(x, y, numpoints, params.q_pts, params.quads);
    cmv[5] = lic6(x, y, numpoints);
    cmv[6] = lic7(x, y, numpoints, params.n_pts, params.dist);
    cmv[7] = lic8(x, y, numpoints, params.k_pts, params.length1);
    cmv[8] = lic9(x, y, numpoints, params.a_pts, params.b_pts, params.radius1);
    cmv[9] = lic10(x, y, numpoints, params.c_pts, params.d_pts, params.epsilon);
    cmv[10] = lic11(x, y, numpoints, params.e_pts, params.f_pts, params.area1);
    cmv[11] = lic12(x, y, numpoints, params.g_pts);
    cmv[12] = lic13(
        x,
        y,
        numpoints,
        params.k_pts,
        params.length1,
        params.length2,
    );
    cmv[13] = lic14(
        x,
        y,
        numpoints,
        params.a_pts,
        params.b_pts,
        params.radius1,
        params.radius2,
    );
    cmv[14] = lic15(
        x,
        y,
        numpoints,
        params.e_pts,
        params.f_pts,
        params.area1,
        params.area2,
    );

    let mut pum = vec![vec![false; 15]; 15];

    for i in 0..15 {
        pum[i][i] = pum_diag[i];
        for j in 0..15 {
            if i != j {
                pum[i][j] = compute_pum_entry(&cmv, lcm, i, j);
            }
        }
    }

    let mut fuv = vec![false; 15];
    for i in 0..15 {
        if !pum[i][i] {
            fuv[i] = true;
        } else {
            let all_true = pum[i].iter().all(|&v| v);
            fuv[i] = all_true;
        }
    }

    let launch = fuv.iter().all(|&v| v);

    DecideOutput::from_fixed(cmv, pum, fuv, launch)
}

fn realcompare(a: f64, b: f64) -> &'static str {
    let eps = 1e-6;
    let diff = a - b;
    if diff < -eps {
        "LT"
    } else if diff > eps {
        "GT"
    } else {
        "EQ"
    }
}

fn distance(x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    ((x2 - x1).powi(2) + (y2 - y1).powi(2)).sqrt()
}

fn angle_at_vertex(x0: f64, y0: f64, x1: f64, y1: f64, x2: f64, y2: f64) -> Option<f64> {
    if (x0 == x1 && y0 == y1) || (x2 == x1 && y2 == y1) {
        return None;
    }

    let v1x = x0 - x1;
    let v1y = y0 - y1;
    let v2x = x2 - x1;
    let v2y = y2 - y1;

    let dot = v1x * v2x + v1y * v2y;
    let mag1 = (v1x.powi(2) + v1y.powi(2)).sqrt();
    let mag2 = (v2x.powi(2) + v2y.powi(2)).sqrt();

    if mag1 < 1e-15 || mag2 < 1e-15 {
        return None;
    }

    let cos_angle = dot / (mag1 * mag2);
    let cos_clamped = cos_angle.max(-1.0).min(1.0);
    Some(cos_clamped.acos())
}

fn triangle_area(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    0.5 * ((x2 - x1) * (y3 - y1) - (x3 - x1) * (y2 - y1)).abs()
}

fn quadrant(x: f64, y: f64) -> usize {
    const EPS: f64 = 1e-10;
    if x > EPS {
        if y > EPS {
            1
        } else if y < -EPS {
            4
        } else {
            1
        }
    } else if x < -EPS {
        if y > EPS {
            2
        } else if y < -EPS {
            3
        } else {
            2
        }
    } else {
        if y > EPS {
            1
        } else if y < -EPS {
            3
        } else {
            1
        }
    }
}

fn lic1(x: &[f64], y: &[f64], numpoints: usize, length1: f64) -> bool {
    for i in 0..numpoints - 1 {
        let d = distance(x[i], y[i], x[i + 1], y[i + 1]);
        if realcompare(d, length1) == "GT" {
            return true;
        }
    }
    false
}

fn lic2(x: &[f64], y: &[f64], numpoints: usize, radius1: f64) -> bool {
    for i in 0..numpoints - 2 {
        if !points_in_circle(x, y, i, i + 1, i + 2, radius1) {
            return true;
        }
    }
    false
}

fn points_in_circle(x: &[f64], y: &[f64], i1: usize, i2: usize, i3: usize, radius: f64) -> bool {
    let (x1, y1) = (x[i1], y[i1]);
    let (x2, y2) = (x[i2], y[i2]);
    let (x3, y3) = (x[i3], y[i3]);

    if (x1 == x2 && y1 == y2) || (x2 == x3 && y2 == y3) || (x1 == x3 && y1 == y3) {
        let d1 = distance(x1, y1, x2, y2);
        let d2 = distance(x2, y2, x3, y3);
        let d3 = distance(x1, y1, x3, y3);
        let max_d = d1.max(d2).max(d3);
        return realcompare(max_d, 2.0 * radius) != "GT";
    }

    let a = distance(x1, y1, x2, y2);
    let b = distance(x2, y2, x3, y3);
    let c = distance(x1, y1, x3, y3);

    let s = (a + b + c) / 2.0;
    let area = (s * (s - a) * (s - b) * (s - c)).max(0.0).sqrt();

    if area < 1e-15 {
        return false;
    }

    let circumradius = (a * b * c) / (4.0 * area);
    realcompare(circumradius, radius) != "GT"
}

fn lic3(x: &[f64], y: &[f64], numpoints: usize, epsilon: f64) -> bool {
    for i in 0..numpoints - 2 {
        let angle = match angle_at_vertex(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2]) {
            Some(a) => a,
            None => continue,
        };

        let pi_minus_eps = std::f64::consts::PI - epsilon;
        let pi_plus_eps = std::f64::consts::PI + epsilon;

        if realcompare(angle, pi_minus_eps) == "LT" || realcompare(angle, pi_plus_eps) == "GT" {
            return true;
        }
    }
    false
}

fn lic4(x: &[f64], y: &[f64], numpoints: usize, area1: f64) -> bool {
    for i in 0..numpoints - 2 {
        let area = triangle_area(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2]);
        if realcompare(area, area1) == "GT" {
            return true;
        }
    }
    false
}

fn lic5(x: &[f64], y: &[f64], numpoints: usize, q_pts: usize, quads: usize) -> bool {
    for i in 0..=numpoints - q_pts {
        let mut quads_found = 0usize;
        let mut mask = 0usize;

        for j in 0..q_pts {
            let quad = quadrant(x[i + j], y[i + j]);
            let bit = 1 << (quad - 1);
            if mask & bit == 0 {
                mask |= bit;
                quads_found += 1;
            }
        }

        if quads_found > quads {
            return true;
        }
    }
    false
}

fn lic6(x: &[f64], y: &[f64], numpoints: usize) -> bool {
    for i in 0..numpoints - 1 {
        if x[i + 1] - x[i] < 0.0 {
            return true;
        }
    }
    false
}

fn distance_to_line_segment(px: f64, py: f64, x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    let dx = x2 - x1;
    let dy = y2 - y1;
    let len_sq = dx * dx + dy * dy;

    if len_sq < 1e-15 {
        return distance(px, py, x1, y1);
    }

    let t = ((px - x1) * dx + (py - y1) * dy) / len_sq;
    let t_clamped = t.max(0.0).min(1.0);

    let proj_x = x1 + t_clamped * dx;
    let proj_y = y1 + t_clamped * dy;

    distance(px, py, proj_x, proj_y)
}

fn lic7(x: &[f64], y: &[f64], numpoints: usize, n_pts: usize, dist: f64) -> bool {
    if numpoints < 3 {
        return false;
    }

    for i in 0..=numpoints - n_pts {
        let first_idx = i;
        let last_idx = i + n_pts - 1;

        if x[first_idx] == x[last_idx] && y[first_idx] == y[last_idx] {
            let mut max_d = 0.0;
            for k in first_idx..=last_idx {
                let d = distance(x[first_idx], y[first_idx], x[k], y[k]);
                if d > max_d {
                    max_d = d;
                }
            }
            if realcompare(max_d, dist) == "GT" {
                return true;
            }
        } else {
            for k in first_idx..=last_idx {
                let d = distance_to_line_segment(
                    x[k],
                    y[k],
                    x[first_idx],
                    y[first_idx],
                    x[last_idx],
                    y[last_idx],
                );
                if realcompare(d, dist) == "GT" {
                    return true;
                }
            }
        }
    }
    false
}

fn lic8(x: &[f64], y: &[f64], numpoints: usize, k_pts: usize, length1: f64) -> bool {
    if numpoints < 3 {
        return false;
    }

    for i in 0..=numpoints - k_pts - 2 {
        let j = i + k_pts + 1;
        let d = distance(x[i], y[i], x[j], y[j]);
        if realcompare(d, length1) == "GT" {
            return true;
        }
    }
    false
}

fn lic9(x: &[f64], y: &[f64], numpoints: usize, a_pts: usize, b_pts: usize, radius1: f64) -> bool {
    if numpoints < 5 {
        return false;
    }

    for i in 0..=numpoints - a_pts - b_pts - 3 {
        let j = i + a_pts + 1;
        let k = j + b_pts + 1;
        if !points_in_circle(x, y, i, j, k, radius1) {
            return true;
        }
    }
    false
}

fn lic10(x: &[f64], y: &[f64], numpoints: usize, c_pts: usize, d_pts: usize, epsilon: f64) -> bool {
    if numpoints < 5 {
        return false;
    }

    for i in 0..=numpoints - c_pts - d_pts - 3 {
        let j = i + c_pts + 1;
        let k = j + d_pts + 1;

        let angle = match angle_at_vertex(x[i], y[i], x[j], y[j], x[k], y[k]) {
            Some(a) => a,
            None => continue,
        };

        let pi_minus_eps = std::f64::consts::PI - epsilon;
        let pi_plus_eps = std::f64::consts::PI + epsilon;

        if realcompare(angle, pi_minus_eps) == "LT" || realcompare(angle, pi_plus_eps) == "GT" {
            return true;
        }
    }
    false
}

fn lic11(x: &[f64], y: &[f64], numpoints: usize, e_pts: usize, f_pts: usize, area1: f64) -> bool {
    if numpoints < 5 {
        return false;
    }

    for i in 0..=numpoints - e_pts - f_pts - 3 {
        let j = i + e_pts + 1;
        let k = j + f_pts + 1;
        let area = triangle_area(x[i], y[i], x[j], y[j], x[k], y[k]);
        if realcompare(area, area1) == "GT" {
            return true;
        }
    }
    false
}

fn lic12(x: &[f64], y: &[f64], numpoints: usize, g_pts: usize) -> bool {
    if numpoints < 3 {
        return false;
    }

    for i in 0..=numpoints - g_pts - 2 {
        let j = i + g_pts + 1;
        if x[j] - x[i] < 0.0 {
            return true;
        }
    }
    false
}

fn lic13(x: &[f64], y: &[f64], numpoints: usize, k_pts: usize, length1: f64, length2: f64) -> bool {
    if numpoints < 3 {
        return false;
    }

    let mut found_gt = false;
    let mut found_lt = false;

    for i in 0..=numpoints - k_pts - 2 {
        let j = i + k_pts + 1;
        let d = distance(x[i], y[i], x[j], y[j]);

        if !found_gt && realcompare(d, length1) == "GT" {
            found_gt = true;
        }
        if !found_lt && realcompare(d, length2) == "LT" {
            found_lt = true;
        }

        if found_gt && found_lt {
            return true;
        }
    }

    false
}

fn lic14(
    x: &[f64],
    y: &[f64],
    numpoints: usize,
    a_pts: usize,
    b_pts: usize,
    radius1: f64,
    radius2: f64,
) -> bool {
    if numpoints < 5 {
        return false;
    }

    let mut found_gt = false;
    let mut found_lt = false;

    for i in 0..=numpoints - a_pts - b_pts - 3 {
        let j = i + a_pts + 1;
        let k = j + b_pts + 1;

        let in_circle = points_in_circle(x, y, i, j, k, radius2);
        let not_in_circle = !points_in_circle(x, y, i, j, k, radius1);

        if not_in_circle {
            found_gt = true;
        }
        if in_circle {
            found_lt = true;
        }

        if found_gt && found_lt {
            return true;
        }
    }

    false
}

fn lic15(
    x: &[f64],
    y: &[f64],
    numpoints: usize,
    e_pts: usize,
    f_pts: usize,
    area1: f64,
    area2: f64,
) -> bool {
    if numpoints < 5 {
        return false;
    }

    let mut found_gt = false;
    let mut found_lt = false;

    for i in 0..=numpoints - e_pts - f_pts - 3 {
        let j = i + e_pts + 1;
        let k = j + f_pts + 1;
        let area = triangle_area(x[i], y[i], x[j], y[j], x[k], y[k]);

        if !found_gt && realcompare(area, area1) == "GT" {
            found_gt = true;
        }
        if !found_lt && realcompare(area, area2) == "LT" {
            found_lt = true;
        }

        if found_gt && found_lt {
            return true;
        }
    }

    false
}

fn compute_pum_entry(cmv: &[bool], lcm: &[Vec<String>], i: usize, j: usize) -> bool {
    let connector = &lcm[i][j];

    match connector.as_str() {
        "NOTUSED" => true,
        "ANDD" => cmv[i] && cmv[j],
        "ORR" => cmv[i] || cmv[j],
        _ => true,
    }
}
